code.C:
#include <stdio.h>
#define MOD 10000
long long dp[1000001];
int main() {
    int N;
    scanf("%d", &N);
    dp[0] = 1;
    dp[1] = 1;
    dp[2] = 3;
    for (int i = 3; i <= N; i++) {
        dp[i] = (dp[i-1] + dp[i-2] + dp[i-3]) % MOD;
    }
    printf("%lld\n", dp[N]);
    return 0;
}

